<style>
div{
/* color-mix() - 100 chars exactly - stays inline (at boundary) */
color:color-mix(in oklch,oklch(0.5555555 0.22222 180) 25%,oklch(0.88888888 0.155555 90) 75%);

/* color-mix() - 101 chars - wraps (exceeds print_width) */
color:color-mix(in oklch,oklch(0.55555555 0.22222 180) 25%,oklch(0.88888888 0.155555 90) 75%);
}
</style>
